            .map(|rd| {
                rd.filter(|e| {
                    e.as_ref()
                        .ok()
                        .and_then(|e| e.path().extension().map(|x| x == "bop"))
                        .unwrap_or(false)
                })
                .count()
            })
            .unwrap_or(0);
        let mut available_slots = max_workers.saturating_sub(running_count);

