    39→pub fn scan_cards_for_cleanup(root: &Path, failed_age_days: u32) -> anyhow::Result<ScanResult> {
    40→    let states = vec!["drafts", "pending", "running", "done", "failed", "merged"];
    41→    let mut result = ScanResult::default();
    42→
    43→    for state in &states {
    44→        scan_state_dir_for_cleanup(root, state, failed_age_days, &mut result)?;
    45→
    46→        // Also scan team-* directories
    47→        if let Ok(entries) = fs::read_dir(root) {
    48→            let mut team_dirs: Vec<_> = entries
    49→                .flatten()
    50→                .filter(|e| {
    51→                    let name = e.file_name();
    52→                    let s = name.to_string_lossy();
    53→                    e.path().is_dir() && s.starts_with("team-")
    54→                })
    55→                .collect();
    56→            team_dirs.sort_by_key(|e| e.file_name());
    57→
    58→            for entry in team_dirs {
    59→                scan_state_dir_for_cleanup(&entry.path(), state, failed_age_days, &mut result)?;
    60→            }
    61→        }
    62→    }
    63→
    64→    Ok(result)
    65→}
    66→
    67→fn scan_state_dir_for_cleanup(
    68→    dir: &Path,
    69→    state: &str,
    70→    failed_age_days: u32,
    71→    result: &mut ScanResult,
    72→) -> anyhow::Result<()> {
    73→    let state_dir = dir.join(state);
    74→    if !state_dir.exists() {
    75→        return Ok(());
    76→    }
    77→
    78→    if let Ok(entries) = fs::read_dir(&state_dir) {
    79→        for entry in entries.flatten() {
    80→            let card_path = entry.path();
    81→            if !card_path.is_dir() {
    82→                continue;
    83→            }
    84→
    85→            let ext = card_path.extension().and_then(|e| e.to_str());
    86→            if !matches!(ext, Some("bop") | Some("jobcard")) {
    87→                continue;
    88→            }
    89→
    90→            // Check for corrupt card (no readable meta.json)
    91→            if bop_core::read_meta(&card_path).is_err() {
    92→                result.corrupt_cards.push(card_path.clone());
    93→                continue;
    94→            }
    95→
    96→            // Check for old failed cards
    97→            if state == "failed" {
    98→                if let Ok(metadata) = fs::metadata(&card_path) {
    99→                    if let Ok(modified) = metadata.modified() {
   100→                        let age = std::time::SystemTime::now()
   101→                            .duration_since(modified)
   102→                            .unwrap_or_default();
   103→                        if age.as_secs() > (failed_age_days as u64 * 86400) {
   104→                            result.old_failed_cards.push(card_path.clone());
   105→                        }
   106→                    }
   107→                }
   108→            }
   109→
   110→            // Check for orphan running cards (empty with dead PID)
   111→            if state == "running" {
   112→                // Check if card is empty (no meaningful output/logs)
   113→                let is_empty = card_path
   114→                    .join("output")
   115→                    .read_dir()
   116→                    .ok()
   117→                    .and_then(|mut d| if d.next().is_none() { Some(true) } else { None })
   118→                    .unwrap_or(false);
   119→
   120→                if is_empty {
   121→                    // Check if there are any log files
   122→                    let has_logs = card_path
   123→                        .join("logs")
   124→                        .read_dir()
   125→                        .ok()
   126→                        .and_then(|mut d| d.next())
   127→                        .is_some();
   128→
   129→                    // If empty and no logs, likely orphaned
   130→                    if !has_logs {
   131→                        result.orphan_running_cards.push(card_path.clone());
   132→                    }
   133→                }
   134→            }
   135→
   136→            // Check for target/ directories inside cards
   137→            let target_dir = card_path.join("target");
   138→            if target_dir.exists() && target_dir.is_dir() {
   139→                result.target_dirs.push(target_dir);
   140→            }
   141→        }
   142→    }
   143→
   144→    Ok(())
   145→}
