   147→// ── Helper: Calculate directory size ────────────────────────────────────────
   148→
   149→fn dir_size(path: &Path) -> u64 {
   150→    let mut total = 0u64;
   151→    if let Ok(entries) = fs::read_dir(path) {
   152→        for entry in entries.flatten() {
   153→            let path = entry.path();
   154→            if let Ok(metadata) = fs::metadata(&path) {
   155→                if metadata.is_dir() {
   156→                    total += dir_size(&path);
   157→                } else {
   158→                    total += metadata.len();
   159→                }
   160→            }
   161→        }
   162→    }
   163→    total
   164→}
